-- `BETWEEN SYMMETRIC a AND b` holds when the value lies between the two bounds
-- in either order — the pair of asymmetric tests, AND-ed rather than OR-ed for
-- NOT BETWEEN. ASYMMETRIC is the default written out.

SELECT 1 BETWEEN SYMMETRIC 2 AND 0;
SELECT 1 BETWEEN SYMMETRIC 0 AND 2;
SELECT 3 BETWEEN SYMMETRIC 2 AND 0;
SELECT 2 BETWEEN SYMMETRIC 2 AND 2;
SELECT 1 NOT BETWEEN SYMMETRIC 2 AND 0;
SELECT 3 NOT BETWEEN SYMMETRIC 2 AND 0;
SELECT 'b' BETWEEN SYMMETRIC 'c' AND 'a';

-- NULL anywhere makes it unknown, as the asymmetric form does
SELECT NULL BETWEEN SYMMETRIC 1 AND 2;
SELECT 1 BETWEEN SYMMETRIC NULL AND 2;
SELECT 1 NOT BETWEEN SYMMETRIC NULL AND 2;

-- ASYMMETRIC is what BETWEEN already meant
SELECT 1 BETWEEN ASYMMETRIC 0 AND 2;
SELECT 1 BETWEEN ASYMMETRIC 2 AND 0;
SELECT 1 NOT BETWEEN ASYMMETRIC 2 AND 0;
SELECT 1 BETWEEN 0 AND 2;
SELECT 1 BETWEEN 2 AND 0;
SELECT 1 NOT BETWEEN 2 AND 0;

CREATE TABLE betsym (a int, b int);
INSERT INTO betsym VALUES (1,10),(1,20),(2,30),(2,40),(3,50);
SELECT a, b FROM betsym WHERE b BETWEEN SYMMETRIC 40 AND 20 ORDER BY a, b;
SELECT a, b FROM betsym WHERE b NOT BETWEEN SYMMETRIC 40 AND 20 ORDER BY a, b;
SELECT a, b FROM betsym WHERE b BETWEEN SYMMETRIC 20 AND 40 ORDER BY a, b;
SELECT b BETWEEN SYMMETRIC 40 AND a*10 FROM betsym ORDER BY b;
DROP TABLE betsym;
